mapper.select:
SELECT t.id, -- 主键 t.name, t.description, t.status, t.textbook_id AS textbookId, t.textbook_catalog_id AS textbookCatalogId, t.max_attempts AS maxAttempts, t.score_policy AS scorePolicy, t.creator, u.nickname AS creatorName, -- ⭐ 新增：从用户表取创建人名称 t.add_datetime AS addDatetime, COUNT(qbl.id) AS questionCount FROM teaching_question_bank t LEFT JOIN questions_banks_list qbl ON t.id = qbl.bank_id LEFT JOIN sys_tbuser u ON t.creator = u.id
AND t.name LIKE CONCAT('%', #{param.name}, '%')
AND t.description LIKE CONCAT('%', #{param.description}, '%')
AND t.status = #{param.status}
AND t.textbook_id = #{param.textbookId}
AND t.textbook_catalog_id = #{param.textbookCatalogId}
AND t.max_attempts = #{param.maxAttempts}
AND t.score_policy = #{param.scorePolicy}
AND t.textbook_catalog_id IS NULL
GROUP BY t.id, t.name, t.description, t.status, t.textbook_id, t.textbook_catalog_id, t.max_attempts, t.score_policy, t.creator, u.nickname, t.add_datetime -- ⭐ GROUP BY 里要加上 u.username ORDER BY t.add_datetime
ASC DESC

SELECT tqb.id AS bankId, tqb.name AS bankName, tqb.textbook_catalog_id AS catalogId, tc.catalog_name AS catalogName, COUNT(DISTINCT ser.id) AS pendingReviewCount FROM teaching_question_bank tqb LEFT JOIN textbook_catalog tc ON tqb.textbook_catalog_id = tc.id LEFT JOIN student_exercises_record ser ON tqb.id = ser.teaching_question_bank_id AND ser.status = 1 WHERE tqb.textbook_id = #{textbookId,jdbcType=BIGINT}
AND tqb.textbook_catalog_id = #{textbookCatalogId,jdbcType=BIGINT}
AND tqb.name LIKE CONCAT('%', #{teachingQuestionBankName,jdbcType=VARCHAR}, '%')
GROUP BY tqb.id, tqb.name, tqb.textbook_catalog_id, tc.catalog_name ORDER BY CASE WHEN COUNT(DISTINCT ser.id) > 0 THEN 0 ELSE 1 END ASC, tqb.textbook_catalog_id ASC, tqb.id ASC
